mapper.select:
		/*
             SQL ID : BbsInfoLangDAO.updateBbsInfoLang
             설  명 : 게시판 언어 수정
         */


		MERGE INTO TB_HOME_BBS_INFO_LANG T 	
		USING(
            SELECT
                  #{bbsId} AS BBS_ID
                , #{langCd} AS LANG_CD
            FROM DUAL
        ) S 
        ON (T.BBS_ID = S.BBS_ID AND T.LANG_CD = S.LANG_CD)
        WHEN MATCHED THEN
            UPDATE SET
            	T.BBSNM = #{bbsNm}
			  , T.BBS_EXPLN = #{bbsDesc}
		WHEN NOT MATCHED THEN
            INSERT(
	            BBS_ID
				, LANG_CD
				, BBSNM
				, BBS_EXPLN
			) VALUES (
				  #{bbsId}
				, #{langCd}
				, #{bbsNm}
				, #{bbsDesc}
	        )

		/*
             SQL ID : BbsInfoLangDAO.deleteBbsInfoLangAll
             설  명 : 게시판 언어 전체삭제
         */
		DELETE FROM TB_HOME_BBS_INFO_LANG
		WHERE BBS_ID = #{bbsId}
